import React, { useState } from "react";
import "./index.css";

import iconStar from "./images/icon-star.svg";
import illustrationThankYou from "./images/illustration-thank-you.svg";

function RatingApp() {
  const [rating, setRating] = useState(null);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = () => {
    if (rating !== null) {
      setSubmitted(true);
    }
  };

  if (submitted) {
    return (
      <main className="container">
        <div className="card thank-you">
          <img
            src={illustrationThankYou}
            alt="Zahvala"
            className="img-thank-you"
          />
          <div className="selection-badge">Odabrali ste {rating} od 5</div>
          <h1>Hvala vam!</h1>
          <p>
            Cijenimo što ste izdvojili vrijeme za ocjenu. Ako vam ikada zatreba
            dodatna podrška, slobodno nas kontaktirajte!
          </p>
        </div>
      </main>
    );
  }

  return (
    <main className="container">
      <div className="card">
        <div className="icon-box">
          <img src={iconStar} alt="Zvijezda" />
        </div>

        <h1>Kako smo prošli?</h1>
        <p>
          Molimo vas da nas ocijenite na temelju vašeg iskustva. Svaka povratna
          informacija nam pomaže da postanemo bolji!
        </p>

        <div className="rating-row">
          {[1, 2, 3, 4, 5].map((num) => (
            <button
              key={num}
              type="button"
              className={`circle-btn ${rating === num ? "active" : ""}`}
              onClick={() => setRating(num)}
            >
              {num}
            </button>
          ))}
        </div>

        <button
          className="submit-btn"
          onClick={handleSubmit}
          disabled={rating === null}
        >
          POŠALJI
        </button>
      </div>
    </main>
  );
}

export default RatingApp;
